// Transform CrUX responses to core_web_vitals schema
const items = $input.all();
const today = new Date().toISOString().split('T')[0];
const records = [];

const devices = ['mobile', 'desktop'];
items.forEach((item, idx) => {
  const data = item.json.record || {};
  const metrics = data.metrics || {};

  const lcp = metrics.largest_contentful_paint || {};
  const inp = metrics.interaction_to_next_paint || metrics.first_input_delay || {};
  const cls = metrics.cumulative_layout_shift || {};

  records.push({
    collected_date: today,
    device: devices[idx],
    lcp_good_percent: lcp.histogram?.[0]?.density * 100 || null,
    lcp_needs_improvement_percent: lcp.histogram?.[1]?.density * 100 || null,
    lcp_poor_percent: lcp.histogram?.[2]?.density * 100 || null,
    lcp_p75: lcp.percentiles?.p75 || null,
    inp_good_percent: inp.histogram?.[0]?.density * 100 || null,
    inp_needs_improvement_percent: inp.histogram?.[1]?.density * 100 || null,
    inp_poor_percent: inp.histogram?.[2]?.density * 100 || null,
    inp_p75: inp.percentiles?.p75 || null,
    cls_good_percent: cls.histogram?.[0]?.density * 100 || null,
    cls_needs_improvement_percent: cls.histogram?.[1]?.density * 100 || null,
    cls_poor_percent: cls.histogram?.[2]?.density * 100 || null,
    cls_p75: cls.percentiles?.p75 || null
  });
});

return records.map(r => ({ json: r }));
